import{_ as t,c as o,o as r,ag as a}from"./chunks/framework.Bw-5EFTY.js";const g=JSON.parse('{"title":"DAG Scheduler Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-scheduler/SPEC.md","filePath":"packages/dag-scheduler/SPEC.md"}'),i={name:"packages/dag-scheduler/SPEC.md"};function c(s,e,d,n,l,u){return r(),o("div",null,e[0]||(e[0]=[a('<h1 id="dag-scheduler-specification" tabindex="-1">DAG Scheduler Specification <a class="header-anchor" href="#dag-scheduler-specification" aria-label="Permalink to &quot;DAG Scheduler Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Owns schedule evaluation, scheduled run triggering, batch triggering, and catchup logic for DAG runs. Computes scheduling windows, validates time ranges, and delegates actual run creation to <code>dag-runtime</code>&#39;s <code>RunOrchestratorService</code>.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Depends on <code>dag-core</code> for domain contracts, error builders, and port interfaces.</li><li>Depends on <code>dag-runtime</code> for <code>RunOrchestratorService</code> and <code>IStartRunResult</code> (known sibling dependency).</li><li>Does not execute task payloads directly -- that responsibility belongs to <code>dag-worker</code>.</li><li>Does not own API response shaping -- that belongs to <code>dag-api</code>.</li><li>Does not own cron expression parsing or external scheduler integration (out of scope for this package).</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>Single-service architecture:</p><ul><li><strong>SchedulerTriggerService</strong> (<code>services/scheduler-trigger-service.ts</code>): Accepts a <code>RunOrchestratorService</code> instance via constructor injection. Provides three operations: <ol><li><code>triggerScheduledRun</code> -- triggers a single scheduled run with a logical date.</li><li><code>triggerScheduledBatch</code> -- triggers multiple scheduled runs sequentially, failing fast on any error.</li><li><code>triggerCatchup</code> -- computes time slots over a date range at a given interval and triggers a run for each slot. Validates date parsing, interval positivity, slot count limits, and range ordering.</li></ol></li></ul><h3 id="behavioral-contracts" tabindex="-1">Behavioral Contracts <a class="header-anchor" href="#behavioral-contracts" aria-label="Permalink to &quot;Behavioral Contracts&quot;">​</a></h3><h4 id="catchup-slot-computation" tabindex="-1">Catchup Slot Computation <a class="header-anchor" href="#catchup-slot-computation" aria-label="Permalink to &quot;Catchup Slot Computation&quot;">​</a></h4><p>The slot count formula and loop condition must be consistent — i.e., the number of slots the formula predicts must equal the number of iterations the loop produces for all valid inputs.</p><p><strong>Current gap</strong>: The implementation uses <code>Math.floor(spanMs / interval) + 1</code> for the slot count and <code>cursorEpochMs &lt;= rangeEndEpochMs</code> for the loop condition. When the range exactly aligns with slot boundaries, the <code>+1</code> causes the formula to overcount by 1 relative to the actual slots needed. For example, range <code>[T, T+3000ms]</code> with 1000ms interval:</p><ul><li>Formula: <code>Math.floor(3000 / 1000) + 1 = 4</code></li><li>Loop (<code>&lt;=</code>): slots at T, T+1000, T+2000, T+3000 = 4 iterations</li></ul><p>The formula and loop are internally consistent in this case (both produce 4). However, the <code>+1</code> creates a bias: a range of <code>[T, T]</code> (zero span) produces 1 slot, and each additional interval adds exactly 1 more slot. Whether this &quot;inclusive endpoint&quot; semantics is intended should be clarified. If half-open <code>[start, end)</code> semantics are desired instead, both the formula and loop must change together:</p><ul><li>Formula: <code>Math.ceil(spanMs / slotIntervalMs)</code></li><li>Loop: <code>cursorEpochMs &lt; rangeEndEpochMs</code></li></ul><p>The chosen semantics must be documented explicitly and the <code>maxSlots</code> validation must use the same formula as the loop to prevent discrepancies.</p><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for:</p><ul><li><code>IScheduledTriggerRequest</code> -- single scheduled run request (dagId, version, logicalDate, input)</li><li><code>IScheduledBatchTriggerRequest</code> -- batch of scheduled trigger items</li><li><code>IScheduledBatchTriggerResult</code> -- batch result with started runs</li><li><code>ICatchupTriggerRequest</code> -- catchup request (dagId, version, rangeStart, rangeEnd, slotIntervalMs, maxSlots, input)</li><li><code>ICatchupTriggerResult</code> -- catchup result (requestedSlotCount, startedRuns)</li></ul><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><ul><li><code>SchedulerTriggerService</code> -- main service class <ul><li><code>constructor(runOrchestrator: RunOrchestratorService)</code> -- accepts a pre-configured runtime orchestrator</li><li><code>triggerScheduledRun(request): Promise&lt;TResult&lt;IStartRunResult, IDagError&gt;&gt;</code></li><li><code>triggerScheduledBatch(request): Promise&lt;TResult&lt;IScheduledBatchTriggerResult, IDagError&gt;&gt;</code></li><li><code>triggerCatchup(request): Promise&lt;TResult&lt;ICatchupTriggerResult, IDagError&gt;&gt;</code></li></ul></li></ul><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li>Accepts a <code>RunOrchestratorService</code> instance via constructor injection. The orchestrator itself accepts <code>IStoragePort</code>, <code>IQueuePort</code>, and <code>IClockPort</code> from <code>dag-core</code>, allowing consumers to provide custom port implementations for different storage/queue backends.</li><li>No abstract classes to extend; the service is used directly.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>All errors use <code>IDagError</code> from <code>dag-core</code> with <code>category: &#39;validation&#39;</code>:</p><ul><li><code>DAG_VALIDATION_INVALID_LOGICAL_DATE</code> -- catchup range dates are not valid ISO-8601</li><li><code>DAG_VALIDATION_INVALID_SLOT_INTERVAL</code> -- <code>slotIntervalMs</code> is zero or negative</li><li><code>DAG_VALIDATION_INVALID_MAX_SLOTS</code> -- <code>maxSlots</code> is zero or negative</li><li><code>DAG_VALIDATION_INVALID_CATCHUP_RANGE</code> -- end date is before start date</li><li><code>DAG_VALIDATION_CATCHUP_RANGE_EXCEEDS_LIMIT</code> -- computed slot count exceeds <code>maxSlots</code></li></ul><p>Additionally, errors from <code>RunOrchestratorService.startRun()</code> propagate directly (definition not found, state transition errors, dispatch errors).</p><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><p>No classes in this package use the <code>implements</code> keyword. All port dependencies are consumed via constructor injection.</p><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. Service classes are standalone (no <code>extends</code>).</p><h3 id="service-dependency-via-di" tabindex="-1">Service Dependency via DI <a class="header-anchor" href="#service-dependency-via-di" aria-label="Permalink to &quot;Service Dependency via DI&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service Class</th><th>Injected Dependency</th><th>Location</th></tr></thead><tbody><tr><td><code>SchedulerTriggerService</code></td><td><code>RunOrchestratorService</code> (dag-runtime)</td><td><code>src/services/scheduler-trigger-service.ts</code></td></tr></tbody></table><h3 id="cross-package-dependencies" tabindex="-1">Cross-Package Dependencies <a class="header-anchor" href="#cross-package-dependencies" aria-label="Permalink to &quot;Cross-Package Dependencies&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Dependency (Owner)</th><th>Consumer Class</th><th>Location</th></tr></thead><tbody><tr><td><code>RunOrchestratorService</code> (dag-runtime)</td><td><code>SchedulerTriggerService</code></td><td><code>src/services/scheduler-trigger-service.ts</code></td></tr><tr><td><code>IStartRunResult</code> (dag-runtime)</td><td><code>SchedulerTriggerService</code></td><td><code>src/services/scheduler-trigger-service.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>Unit tests</strong>: <code>scheduler-trigger-service.test.ts</code></li><li><strong>Integration tests</strong>: <code>scheduler-integration-e2e.test.ts</code></li><li>Tests use in-memory port implementations from <code>dag-core</code>.</li><li>Coverage focus: single trigger delegation, batch sequential execution with fail-fast, catchup slot computation, input validation (date parsing, interval, slot limits, range ordering), error propagation from runtime.</li><li>Run: <code>pnpm --filter @robota-sdk/dag-scheduler test</code></li></ul>',38)]))}const p=t(i,[["render",c]]);export{g as __pageData,p as default};
